"""Таб «Изображения»: логика, OCR/Vision провайдеры и модели."""from __future__ import annotationsimport tkinter as tkfrom pathlib import Pathfrom tkinter import ttkfrom typing import Anyfrom src.core import locmsgfrom src.modules.llm_providers.schemas.chat import LLMChatReasoningEffortfrom src.modules.project.sections.image_processing_config import (    IMAGE_PROCESSING_DEFAULTS,    IMAGE_PROCESSING_KEYS,    IMAGE_PROCESSING_LOGICS,    ImageProcessingConfig,)from src.gui.adapters import (    get_ocr_provider_options,    get_ocr_models_for_provider,    get_vision_provider_options,    get_vision_models_for_provider,)from src.gui.template.components import (    CustomScrollbar,    ScrollableFrame,    SettingsBlock,    grid_section_banner,    grid_sub_block,)from src.gui.template.elements import (    gui_element_header_3,    gui_element_input_description,    gui_element_input_label,    gui_element_input_select,    gui_element_input_spin_float,    gui_element_input_text_area,    gui_element_separator,    gui_element_warning_banner,)from src.gui.template.styles import (    FONT_FAMILY_UI,    PALETTE,    UI_FONT_SIZE,    UI_SETTINGS_BLOCK,    UI_TABS,)_VISION_REASONING_OPTIONS: list[tuple[str, str]] = [    (LLMChatReasoningEffort.DISABLED.value, "project_image_processing.reasoning.off"),    (LLMChatReasoningEffort.LOW.value, "project_image_processing.reasoning.low"),    (LLMChatReasoningEffort.MEDIUM.value, "project_image_processing.reasoning.medium"),    (LLMChatReasoningEffort.HIGH.value, "project_image_processing.reasoning.high"),]_LOGIC_DESC_KEYS: dict[str, str] = {    IMAGE_PROCESSING_LOGICS.skip: "project_image_processing.logic_desc.skip",    IMAGE_PROCESSING_LOGICS.ocr_only: "project_image_processing.logic_desc.ocr_only",    IMAGE_PROCESSING_LOGICS.vision_only: "project_image_processing.logic_desc.vision_only",}_REASONING_API_CODES = frozenset(    {LLMChatReasoningEffort.DISABLED.value, LLMChatReasoningEffort.LOW.value, LLMChatReasoningEffort.MEDIUM.value, LLMChatReasoningEffort.HIGH.value})def _logic_display_for_code(code: str) -> str:    for c, msgid in IMAGE_PROCESSING_LOGICS.options:        if c == code:            return locmsg(msgid)    return locmsg(IMAGE_PROCESSING_LOGICS.options[0][1])def _vision_reasoning_msgid_for_code(code: str) -> str:    for c, msgid in _VISION_REASONING_OPTIONS:        if c == code:            return msgid    return _VISION_REASONING_OPTIONS[0][1]class ImageProcessingSettingsTab(ttk.Frame):    """Режим обработки, плашка про OCR, блоки OCR и Vision с провайдером/моделью."""    SETTINGS_WIDTH_PX = 520    _SEPARATOR_PADX = 12    def __init__(self, parent: ttk.Frame, project_root: Path, **kwargs) -> None:        super().__init__(parent, **kwargs)        self._project_root = project_root        self._file_processing_logic_var = tk.StringVar()        self._logic_code: str = IMAGE_PROCESSING_LOGICS.skip        self._vision_reasoning_code: str = IMAGE_PROCESSING_DEFAULTS.vision_reasoning        self._fp_ocr_frame: ttk.Frame | None = None        self._fp_vision_frame: ttk.Frame | None = None        self._fp_ocr_provider_var = tk.StringVar()        self._fp_ocr_model_var = tk.StringVar()        self._fp_vision_provider_var = tk.StringVar()        self._fp_vision_model_var = tk.StringVar()        self._fp_vision_reasoning_var = tk.StringVar()        self._fp_vision_temperature_var = tk.StringVar()        self._data_processing_warning_banner: tk.Frame | None = None        self._banner_row: int = 0        self._ocr_frame_row: int = 0        self._vision_frame_row: int = 0        self._vision_model_settings_frame: ttk.Frame | None = None        self._vision_model_settings_row: int = 0        self._logic_combo: Any = None        self._logic_description: tk.Widget | None = None        self._article_title_label: ttk.Label | None = None        self._article_text: tk.Text | None = None        self._ocr_section_header: ttk.Label | None = None        self._ocr_intro: tk.Widget | None = None        self._lbl_ocr_provider: tk.Widget | None = None        self._desc_ocr_provider: tk.Widget | None = None        self._lbl_ocr_model: tk.Widget | None = None        self._desc_ocr_model: tk.Widget | None = None        self._vision_section_header: ttk.Label | None = None        self._vision_intro: tk.Widget | None = None        self._lbl_vision_provider: tk.Widget | None = None        self._desc_vision_provider: tk.Widget | None = None        self._lbl_vision_model: tk.Widget | None = None        self._desc_vision_model: tk.Widget | None = None        self._vision_tuning_header: ttk.Label | None = None        self._fp_vision_reasoning_combo: Any = None        self._lbl_reasoning: tk.Widget | None = None        self._desc_reasoning: tk.Widget | None = None        self._lbl_temperature: tk.Widget | None = None        self._desc_temperature: tk.Widget | None = None        self._lbl_extra: tk.Widget | None = None        self._desc_extra: tk.Widget | None = None        self._fp_vision_system_prompt_area: Any = None        self._fp_ocr_provider_combo: Any = None        self._fp_ocr_model_combo: Any = None        self._fp_vision_provider_combo: Any = None        self._fp_vision_model_combo: Any = None        self._fp_vision_temperature_spin: Any = None        self._lbl_mode: tk.Widget | None = None        self._build_ui()    def _sync_logic_code_from_ui(self) -> None:        display = (self._file_processing_logic_var.get() or "").strip()        for code, msgid in IMAGE_PROCESSING_LOGICS.options:            if locmsg(msgid) == display:                self._logic_code = code                return    def _sync_vision_reasoning_from_ui(self) -> None:        display = (self._fp_vision_reasoning_var.get() or "").strip()        for code, msgid in _VISION_REASONING_OPTIONS:            if locmsg(msgid) == display:                self._vision_reasoning_code = code                return    def _build_ui(self) -> None:        padx, pady = UI_TABS["content_padding"]        wrap = ttk.Frame(self)        wrap.pack(fill=tk.BOTH, expand=True, padx=padx, pady=pady)        left_frame = tk.Frame(wrap, width=self.SETTINGS_WIDTH_PX, bg=PALETTE["bg_surface"])        left_frame.pack_propagate(False)        left_frame.pack(side=tk.LEFT, fill=tk.Y, padx=(0, self._SEPARATOR_PADX))        self._scroll = ScrollableFrame(left_frame)        self._scroll.pack(fill=tk.BOTH, expand=True, padx=(0, self._SEPARATOR_PADX))        cfg = UI_SETTINGS_BLOCK        block = SettingsBlock(self._scroll.content_frame)        mode_row = block.add_field_row_frame()        self._logic_combo = gui_element_input_select(            mode_row,            variable=self._file_processing_logic_var,            values=[                display for _code, display in ImageProcessingConfig.get_available_values().processing_logic            ],            width=28,        )        self._lbl_mode = gui_element_input_label(            mode_row, locmsg("project_image_processing.mode_field_label"), wraplength=cfg["column_label_px"]        )        block.finish_field_row(mode_row, self._lbl_mode, self._logic_combo)        self._file_processing_logic_var.trace_add(            "write",            lambda *_: (self._sync_logic_code_from_ui(), self._on_file_processing_logic_change()),        )        self._logic_description = gui_element_input_description(            block.form,            locmsg("project_image_processing.logic_desc.skip"),            wraplength=cfg["container_width_px"],        )        block.add_comment(self._logic_description)        self._data_processing_warning_banner = gui_element_warning_banner(            block.form,            locmsg("project_image_processing.yandex_key_banner"),        )        self._banner_row = block.add_section_banner(self._data_processing_warning_banner)        if ImageProcessingConfig.is_ocr_available():            self._data_processing_warning_banner.grid_remove()        block.add_full_width_row(gui_element_separator(block.form))        ocr_sub, self._fp_ocr_frame, self._ocr_frame_row = block.begin_sub_block()        self._ocr_section_header = gui_element_header_3(            self._fp_ocr_frame, locmsg("project_image_processing.section.model_choice"), pack=False        )        ocr_sub.add_comment(self._ocr_section_header)        self._ocr_intro = gui_element_input_description(            self._fp_ocr_frame,            locmsg("project_image_processing.ocr.intro"),            wraplength=cfg["container_width_px"],        )        ocr_sub.add_comment(self._ocr_intro)        ocr_row0 = ocr_sub.add_field_row_frame()        self._fp_ocr_provider_combo = gui_element_input_select(            ocr_row0,            variable=self._fp_ocr_provider_var,            values=get_ocr_provider_options(),            width=26,        )        self._lbl_ocr_provider = gui_element_input_label(            ocr_row0, locmsg("project_image_processing.label.provider"), wraplength=cfg["column_label_px"]        )        ocr_sub.finish_field_row(ocr_row0, self._lbl_ocr_provider, self._fp_ocr_provider_combo)        self._fp_ocr_provider_var.trace_add("write", lambda *_: self._on_fp_ocr_provider_change())        self._desc_ocr_provider = gui_element_input_description(            self._fp_ocr_frame,            locmsg("project_image_processing.ocr.hint_provider"),            wraplength=cfg["container_width_px"],        )        ocr_sub.add_comment(self._desc_ocr_provider)        ocr_row1 = ocr_sub.add_field_row_frame()        self._fp_ocr_model_combo = gui_element_input_select(            ocr_row1, variable=self._fp_ocr_model_var, values=[], width=26        )        self._lbl_ocr_model = gui_element_input_label(            ocr_row1, locmsg("project_image_processing.label.model"), wraplength=cfg["column_label_px"]        )        ocr_sub.finish_field_row(ocr_row1, self._lbl_ocr_model, self._fp_ocr_model_combo)        self._desc_ocr_model = gui_element_input_description(            self._fp_ocr_frame,            locmsg("project_image_processing.ocr.hint_model"),            wraplength=cfg["container_width_px"],        )        ocr_sub.add_comment(self._desc_ocr_model)        vision_sub, self._fp_vision_frame, self._vision_frame_row = block.begin_sub_block()        self._vision_section_header = gui_element_header_3(            self._fp_vision_frame, locmsg("project_image_processing.section.model_choice"), pack=False        )        vision_sub.add_comment(self._vision_section_header)        self._vision_intro = gui_element_input_description(            self._fp_vision_frame,            locmsg("project_image_processing.vision.intro"),            wraplength=cfg["container_width_px"],        )        vision_sub.add_comment(self._vision_intro)        v_row0 = vision_sub.add_field_row_frame()        self._fp_vision_provider_combo = gui_element_input_select(            v_row0,            variable=self._fp_vision_provider_var,            values=get_vision_provider_options(),            width=26,        )        self._lbl_vision_provider = gui_element_input_label(            v_row0, locmsg("project_image_processing.label.provider"), wraplength=cfg["column_label_px"]        )        vision_sub.finish_field_row(v_row0, self._lbl_vision_provider, self._fp_vision_provider_combo)        self._fp_vision_provider_var.trace_add("write", lambda *_: self._on_fp_vision_provider_change())        self._desc_vision_provider = gui_element_input_description(            self._fp_vision_frame,            locmsg("project_image_processing.vision.hint_provider"),            wraplength=cfg["container_width_px"],        )        vision_sub.add_comment(self._desc_vision_provider)        v_row1 = vision_sub.add_field_row_frame()        self._fp_vision_model_combo = gui_element_input_select(            v_row1, variable=self._fp_vision_model_var, values=[], width=26        )        self._lbl_vision_model = gui_element_input_label(            v_row1, locmsg("project_image_processing.label.model"), wraplength=cfg["column_label_px"]        )        vision_sub.finish_field_row(v_row1, self._lbl_vision_model, self._fp_vision_model_combo)        self._desc_vision_model = gui_element_input_description(            self._fp_vision_frame,            locmsg("project_image_processing.vision.hint_model"),            wraplength=cfg["container_width_px"],        )        vision_sub.add_comment(self._desc_vision_model)        vision_model_sub, self._vision_model_settings_frame, self._vision_model_settings_row = block.begin_sub_block()        vision_model_sub.add_full_width_row(gui_element_separator(self._vision_model_settings_frame))        self._vision_tuning_header = gui_element_header_3(            self._vision_model_settings_frame,            locmsg("project_image_processing.section.model_tuning"),            pack=False,        )        vision_model_sub.add_comment(self._vision_tuning_header)        reason_row = vision_model_sub.add_field_row_frame()        reason_displays = [locmsg(msgid) for _code, msgid in _VISION_REASONING_OPTIONS]        self._fp_vision_reasoning_combo = gui_element_input_select(            reason_row,            variable=self._fp_vision_reasoning_var,            values=reason_displays,            width=26,        )        self._lbl_reasoning = gui_element_input_label(            reason_row, locmsg("project_image_processing.label.reasoning"), wraplength=cfg["column_label_px"]        )        vision_model_sub.finish_field_row(reason_row, self._lbl_reasoning, self._fp_vision_reasoning_combo)        self._fp_vision_reasoning_var.trace_add(            "write", lambda *_: self._sync_vision_reasoning_from_ui()        )        self._desc_reasoning = gui_element_input_description(            self._vision_model_settings_frame,            locmsg("project_image_processing.vision_model.reasoning_hint"),            wraplength=cfg["container_width_px"],        )        vision_model_sub.add_comment(self._desc_reasoning)        temp_row = vision_model_sub.add_field_row_frame()        self._fp_vision_temperature_spin = gui_element_input_spin_float(            temp_row,            textvariable=self._fp_vision_temperature_var,            from_=0.0,            to=2.0,            increment=0.1,            width=6,            decimals=1,        )        self._lbl_temperature = gui_element_input_label(            temp_row, locmsg("project_image_processing.label.temperature"), wraplength=cfg["column_label_px"]        )        vision_model_sub.finish_field_row(temp_row, self._lbl_temperature, self._fp_vision_temperature_spin)        self._desc_temperature = gui_element_input_description(            self._vision_model_settings_frame,            locmsg("project_image_processing.vision_model.temperature_hint"),            wraplength=cfg["container_width_px"],        )        vision_model_sub.add_comment(self._desc_temperature)        self._lbl_extra = gui_element_input_label(            self._vision_model_settings_frame,            locmsg("project_image_processing.label.extra_instructions"),            wraplength=cfg["container_width_px"],        )        vision_model_sub.add_label_row(self._lbl_extra)        self._desc_extra = gui_element_input_description(            self._vision_model_settings_frame,            locmsg("project_image_processing.vision_model.extra_instructions_hint"),            wraplength=cfg["container_width_px"],        )        vision_model_sub.add_comment(self._desc_extra)        self._fp_vision_system_prompt_area = gui_element_input_text_area(            self._vision_model_settings_frame,        )        self._fp_vision_system_prompt_area.set(            IMAGE_PROCESSING_DEFAULTS.vision_system_prompt or ""        )        vision_model_sub.add_full_width_row(self._fp_vision_system_prompt_area)        self._fp_vision_reasoning_var.set(            locmsg(_vision_reasoning_msgid_for_code(IMAGE_PROCESSING_DEFAULTS.vision_reasoning))        )        self._fp_vision_temperature_var.set(            f"{getattr(IMAGE_PROCESSING_DEFAULTS, 'vision_temperature', 0.0):.1f}"        )        self._sync_vision_reasoning_from_ui()        self._on_fp_ocr_provider_change()        self._on_file_processing_logic_change()        sep = tk.Frame(wrap, width=1, bg=PALETTE["border"], highlightthickness=0)        sep.pack(side=tk.LEFT, fill=tk.Y, padx=(0, self._SEPARATOR_PADX))        sep.pack_propagate(False)        right_frame = tk.Frame(wrap, bg=PALETTE["bg_surface"])        right_frame.pack(side=tk.LEFT, fill=tk.BOTH, expand=True)        right_frame.columnconfigure(0, weight=1)        right_frame.rowconfigure(1, weight=1)        self._article_title_label = ttk.Label(            right_frame,            text=locmsg("project_image_processing.notes_title"),            style="RightPanelTitle.TLabel",        )        self._article_title_label.grid(row=0, column=0, sticky=tk.W, pady=(0, 4))        article_container = tk.Frame(right_frame, bg=PALETTE["bg_surface"])        article_container.grid(row=1, column=0, sticky=tk.NSEW)        article_container.columnconfigure(0, weight=1)        article_container.rowconfigure(0, weight=1)        self._article_text = tk.Text(            article_container,            wrap=tk.WORD,            state=tk.DISABLED,            font=(FONT_FAMILY_UI, UI_FONT_SIZE["small"]),            bg=PALETTE["bg_surface"],            fg=PALETTE["text_muted"],            insertbackground=PALETTE["text_muted"],            selectbackground=PALETTE["select_bg"],            selectforeground=PALETTE["select_fg"],            relief=tk.FLAT,            bd=0,            highlightthickness=0,        )        self._article_scrollbar = CustomScrollbar(article_container, command=self._article_text.yview)        self._article_text.configure(yscrollcommand=self._article_scrollbar.set)        self._article_scrollbar.pack(side=tk.RIGHT, fill=tk.Y)        self._article_text.pack(side=tk.LEFT, fill=tk.BOTH, expand=True)        self._article_text.configure(state=tk.NORMAL)        self._article_text.insert(tk.END, locmsg("project_image_processing.article"))        self._article_text.configure(state=tk.DISABLED)    def _on_file_processing_logic_change(self) -> None:        self._sync_logic_code_from_ui()        code = self._logic_code        if self._logic_description is not None:            key = _LOGIC_DESC_KEYS.get(code)            self._logic_description.configure(text=locmsg(key) if key else "")        show_ocr = code == IMAGE_PROCESSING_LOGICS.ocr_only        show_vision = code == IMAGE_PROCESSING_LOGICS.vision_only        if self._data_processing_warning_banner:            if show_ocr and not ImageProcessingConfig.is_ocr_available():                grid_section_banner(self._data_processing_warning_banner, self._banner_row)            else:                self._data_processing_warning_banner.grid_remove()        if self._fp_ocr_frame is not None:            if show_ocr:                grid_sub_block(self._fp_ocr_frame, self._ocr_frame_row)            else:                self._fp_ocr_frame.grid_remove()        if self._fp_vision_frame is not None:            if show_vision:                grid_sub_block(self._fp_vision_frame, self._vision_frame_row)            else:                self._fp_vision_frame.grid_remove()        if self._vision_model_settings_frame is not None:            if show_vision:                grid_sub_block(self._vision_model_settings_frame, self._vision_model_settings_row)            else:                self._vision_model_settings_frame.grid_remove()    def _on_fp_ocr_provider_change(self) -> None:        provider = (self._fp_ocr_provider_var.get() or "").strip().lower()        models = get_ocr_models_for_provider(provider)        self._fp_ocr_model_combo.set_values(models)        if models and (not self._fp_ocr_model_var.get() or self._fp_ocr_model_var.get() not in models):            self._fp_ocr_model_var.set(models[0])    def _on_fp_vision_provider_change(self) -> None:        provider = (self._fp_vision_provider_var.get() or "").strip()        models = get_vision_models_for_provider(provider)        self._fp_vision_model_combo.set_values(models)        if models and (not self._fp_vision_model_var.get() or self._fp_vision_model_var.get() not in models):            self._fp_vision_model_var.set(models[0])    def refresh_options(self) -> None:        """Обновить списки провайдеров/моделей и видимость блоков (при показе экрана)."""        available_logic = ImageProcessingConfig.get_available_values().processing_logic        logic_displays = [display for _code, display in available_logic]        if self._logic_combo is not None:            self._logic_combo.set_values(logic_displays)        current_display = (self._file_processing_logic_var.get() or "").strip()        if logic_displays and current_display not in logic_displays:            self._file_processing_logic_var.set(logic_displays[0])        self._sync_logic_code_from_ui()        if self._fp_ocr_provider_combo is not None:            self._fp_ocr_provider_combo.set_values(get_ocr_provider_options())        self._on_fp_ocr_provider_change()        if self._fp_vision_provider_combo is not None:            self._fp_vision_provider_combo.set_values(get_vision_provider_options())        self._on_fp_vision_provider_change()        self._on_file_processing_logic_change()    def refresh_locale(self) -> None:        """Тексты вкладки после смены языка."""        try:            cfg = UI_SETTINGS_BLOCK            if self._lbl_mode is not None:                self._lbl_mode.configure(                    text=locmsg("project_image_processing.mode_field_label"),                    wraplength=cfg["column_label_px"],                )            if self._ocr_section_header is not None:                self._ocr_section_header.configure(text=locmsg("project_image_processing.section.model_choice"))            if self._vision_section_header is not None:                self._vision_section_header.configure(text=locmsg("project_image_processing.section.model_choice"))            if self._vision_tuning_header is not None:                self._vision_tuning_header.configure(                    text=locmsg("project_image_processing.section.model_tuning")                )            for lbl, key in (                (self._lbl_ocr_provider, "project_image_processing.label.provider"),                (self._lbl_ocr_model, "project_image_processing.label.model"),                (self._lbl_vision_provider, "project_image_processing.label.provider"),                (self._lbl_vision_model, "project_image_processing.label.model"),                (self._lbl_reasoning, "project_image_processing.label.reasoning"),                (self._lbl_temperature, "project_image_processing.label.temperature"),            ):                if lbl is not None:                    lbl.configure(text=locmsg(key), wraplength=cfg["column_label_px"])            if self._lbl_extra is not None:                self._lbl_extra.configure(                    text=locmsg("project_image_processing.label.extra_instructions"),                    wraplength=cfg["container_width_px"],                )            for desc, key in (                (self._ocr_intro, "project_image_processing.ocr.intro"),                (self._desc_ocr_provider, "project_image_processing.ocr.hint_provider"),                (self._desc_ocr_model, "project_image_processing.ocr.hint_model"),                (self._vision_intro, "project_image_processing.vision.intro"),                (self._desc_vision_provider, "project_image_processing.vision.hint_provider"),                (self._desc_vision_model, "project_image_processing.vision.hint_model"),                (self._desc_reasoning, "project_image_processing.vision_model.reasoning_hint"),                (self._desc_temperature, "project_image_processing.vision_model.temperature_hint"),                (self._desc_extra, "project_image_processing.vision_model.extra_instructions_hint"),            ):                if desc is not None:                    desc.configure(text=locmsg(key), wraplength=cfg["container_width_px"])            if self._data_processing_warning_banner is not None and self._data_processing_warning_banner.winfo_exists():                children = self._data_processing_warning_banner.winfo_children()                if len(children) >= 2:                    children[1].configure(text=locmsg("project_image_processing.yandex_key_banner"))            if self._article_title_label is not None and self._article_title_label.winfo_exists():                self._article_title_label.configure(text=locmsg("project_image_processing.notes_title"))            if self._article_text is not None:                self._article_text.configure(state=tk.NORMAL)                self._article_text.delete("1.0", tk.END)                self._article_text.insert(tk.END, locmsg("project_image_processing.article"))                self._article_text.configure(state=tk.DISABLED)            self.refresh_options()            self._file_processing_logic_var.set(_logic_display_for_code(self._logic_code))            self._sync_logic_code_from_ui()            reason_displays = [locmsg(msgid) for _code, msgid in _VISION_REASONING_OPTIONS]            if self._fp_vision_reasoning_combo is not None:                self._fp_vision_reasoning_combo.set_values(reason_displays)            self._fp_vision_reasoning_var.set(locmsg(_vision_reasoning_msgid_for_code(self._vision_reasoning_code)))            self._sync_vision_reasoning_from_ui()            self._on_file_processing_logic_change()        except tk.TclError:            pass    def load_image_processing(self, data: dict[str, Any] | None) -> None:        """Заполняет виджеты из секции image_processing."""        data = data or {}        logic_code = data.get(IMAGE_PROCESSING_KEYS.image_processing_logic, IMAGE_PROCESSING_LOGICS.skip)        if isinstance(logic_code, str):            logic_code = logic_code.strip().lower()        else:            logic_code = IMAGE_PROCESSING_LOGICS.skip        if logic_code not in IMAGE_PROCESSING_LOGICS.valid_codes:            logic_code = IMAGE_PROCESSING_LOGICS.skip        self._logic_code = logic_code        self._file_processing_logic_var.set(_logic_display_for_code(logic_code))        self._sync_logic_code_from_ui()        self._fp_ocr_provider_var.set(            data.get(IMAGE_PROCESSING_KEYS.ocr_provider, IMAGE_PROCESSING_DEFAULTS.ocr_provider)        )        self._fp_ocr_model_var.set(data.get(IMAGE_PROCESSING_KEYS.ocr_model, IMAGE_PROCESSING_DEFAULTS.ocr_model))        self._fp_vision_provider_var.set(data.get(IMAGE_PROCESSING_KEYS.vision_provider, "") or "")        self._fp_vision_model_var.set(data.get(IMAGE_PROCESSING_KEYS.vision_model, "") or "")        reason_code = (data.get(IMAGE_PROCESSING_KEYS.vision_reasoning) or "").strip().lower()        if reason_code not in _REASONING_API_CODES:            reason_code = IMAGE_PROCESSING_DEFAULTS.vision_reasoning        self._vision_reasoning_code = reason_code        self._fp_vision_reasoning_var.set(locmsg(_vision_reasoning_msgid_for_code(reason_code)))        self._sync_vision_reasoning_from_ui()        system_prompt = data.get(IMAGE_PROCESSING_KEYS.vision_system_prompt)        if system_prompt is None:            system_prompt = IMAGE_PROCESSING_DEFAULTS.vision_system_prompt or ""        elif not isinstance(system_prompt, str):            system_prompt = ""        self._fp_vision_system_prompt_area.set(system_prompt)        t = data.get(IMAGE_PROCESSING_KEYS.vision_temperature)        if t is not None:            try:                tf = max(0.0, min(2.0, float(t)))                self._fp_vision_temperature_var.set(f"{tf:.1f}")            except (TypeError, ValueError):                self._fp_vision_temperature_var.set(f"{IMAGE_PROCESSING_DEFAULTS.vision_temperature:.1f}")        else:            self._fp_vision_temperature_var.set(f"{IMAGE_PROCESSING_DEFAULTS.vision_temperature:.1f}")        self._on_fp_ocr_provider_change()        self._on_file_processing_logic_change()        show_ocr = logic_code == IMAGE_PROCESSING_LOGICS.ocr_only        show_vision = logic_code == IMAGE_PROCESSING_LOGICS.vision_only        if show_ocr:            ocr_opts = get_ocr_provider_options()            if ocr_opts and (not self._fp_ocr_provider_var.get() or self._fp_ocr_provider_var.get() not in ocr_opts):                self._fp_ocr_provider_var.set(ocr_opts[0])            self._on_fp_ocr_provider_change()        if show_vision:            vision_opts = get_vision_provider_options()            if vision_opts and (                not self._fp_vision_provider_var.get()                or self._fp_vision_provider_var.get() not in vision_opts            ):                self._fp_vision_provider_var.set(vision_opts[0])            self._on_fp_vision_provider_change()    def get_image_processing_data(self) -> dict[str, Any]:        """Собирает данные секции image_processing из виджетов."""        self._sync_logic_code_from_ui()        self._sync_vision_reasoning_from_ui()        return {            IMAGE_PROCESSING_KEYS.image_processing_logic: self._logic_code,            IMAGE_PROCESSING_KEYS.ocr_provider: (self._fp_ocr_provider_var.get() or "").strip().lower()            or IMAGE_PROCESSING_DEFAULTS.ocr_provider,            IMAGE_PROCESSING_KEYS.ocr_model: (self._fp_ocr_model_var.get() or IMAGE_PROCESSING_DEFAULTS.ocr_model).strip(),            IMAGE_PROCESSING_KEYS.vision_provider: (self._fp_vision_provider_var.get() or "").strip(),            IMAGE_PROCESSING_KEYS.vision_model: (self._fp_vision_model_var.get() or "").strip(),            IMAGE_PROCESSING_KEYS.vision_reasoning: self._vision_reasoning_code,            IMAGE_PROCESSING_KEYS.vision_system_prompt: (self._fp_vision_system_prompt_area.get() or "").strip(),            IMAGE_PROCESSING_KEYS.vision_temperature: self._fp_vision_temperature_spin.get_float(),        }